    },
    {
      "role": "user",
      "content": "Script: {{ $json.script }}\n\nGive me 3 Pexels search keywords for this {{ $json.category }} video."
    }
  ],
  "temperature": 0.5,
  "max_tokens": 100
}

parameters.jsCode:
const response = $input.first().json;
const scriptData = $('Parse Script').first().json;
let keywords;
try {
  const raw = response.choices?.[0]?.message?.content?.trim() || '[]';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  keywords = JSON.parse(cleaned);
  if (!Array.isArray(keywords)) throw new Error('not array');
} catch(e) {
  keywords = [scriptData.category, 'technology', 'future'];
}
return [{
  json: {
    keywords,
    searchQuery: keywords[0] || scriptData.category,
    script: scriptData.script,
    topic: scriptData.topic,
    category: scriptData.category,
    duration: scriptData.duration,
    userEmail: scriptData.userEmail,
    pexelsKey: scriptData.pexelsKey,
    json2videoKey: scriptData.json2videoKey,
    elevenLabsKey: scriptData.elevenLabsKey
  }
}];

const pexelsData = $input.first().json;
const keywordData = $('Parse Keywords').first().json;
const scriptData = $('Parse Script').first().json;

// Extract video URLs from Pexels
const videos = pexelsData.videos || [];
const videoUrls = videos.map(v => {
  const files = v.video_files || [];
  // Get HD portrait file
  const hdFile = files.find(f => f.quality === 'hd' && f.height > f.width) ||
                 files.find(f => f.height > f.width) ||
                 files[0];
  return hdFile?.link || '';
}).filter(url => url !== '');

// Fallback URLs if Pexels fails
const fallbackUrls = [
  'https://www.pexels.com/download/video/3129671/',
  'https://www.pexels.com/download/video/3550341/',
  'https://www.pexels.com/download/video/4065898/'
];

const finalUrls = videoUrls.length > 0 ? videoUrls : fallbackUrls;

return [{
  json: {
    videoUrl1: finalUrls[0] || fallbackUrls[0],
    videoUrl2: finalUrls[1] || fallbackUrls[1],
    videoUrl3: finalUrls[2] || fallbackUrls[2],
    script: scriptData.script,
    topic: scriptData.topic,
    category: scriptData.category,
    duration: scriptData.duration,
    userEmail: scriptData.userEmail,
    json2videoKey: keywordData.json2videoKey
  }
}];

